};

scwin.onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};

scwin.gr_hsnInfo_onviewchange = function (info) {
    console.log(info);
    if (info.colId == "pkgUnit") {
        scwin.f_GridPopUp("PackageCode", info.rowIndex, "T", "F", "F");
