};

scwin.gr_hsnInfo_onafteredit = function (rowIndex, columnIndex, value) {

    let columnId = gr_hsnInfo.getColumnID(columnIndex);

    console.log("gr_hsnInfo_onafteredit columnId : " + columnId + " : " + rowIndex);

    if (columnId == "pkgUnit") {
